INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1534, 195401, 12, 1974, '[转贴]溃败的守望者', '通过写信的方式，将自己的分崩离析的生活维系起来，是《挪威的森林》最大特色。文章中那些焰火一样的美丽、烟花一样的情感，是一条长长的小溪，穿行在都市之外的天空下。深居简出的主人公、浓厚的怀旧感伤色彩、冷峻的嘲讽、艰涩的调侃在冰冷的城市、无边的水泥构建的庞大的灰色建筑中，建立一个属于自己的不灭的精神的天堂。我很难想象，村上这个忠于老婆和家庭，白天跑步、独自在自己庭院中漫步的孤独的人，在日本的文学上道路上不经意的就留下自己的深深的足迹，成为物质文明高度发达的社会中，精神文明日益溃败的一个坚实的守望者。 
<br>　　现在还能感觉主人公的空虚，如张开大口的无边的岁月。《挪威的森林》首先是一部爱情小说，我开始看这部小说的时候，就是从感情的角度出发的。不象今天，有很多人给我推荐这样那样我从来不看的书籍，因此我对村上的了解是自发的，这种了解来自他的文字和小说。那种后现代的虚无、荒诞和失落，其实也影响网络上很多的写手。尤其是那些自持有才华的写手，对村上的膜拜是无出其右的，但是或略文字最终的目的为了准确的表达一种情绪、一种情感的。比如良知、正义、同情、深刻、思考等。爱情，作为基调的小说中，村上给了我另外的一面，是一个奇特的符号，一个不能明晰的事件，在过去的不能视见的光阴中发生过。大学的很多夜晚，我想自己就是那个在街道上晃荡的少年，希望有一个还算干净的旅馆，邂逅几个漂亮的美女，在醉眼朦胧中，用快餐的爱情，刻意的忘却生存带来的压力和思考，忘记关于明天的天空和道路；也希望那种模糊的情感，影响到我的心灵、田地和行走的路径。但是，每次醒来，都是寂静的夜。水房中的滴水声、楼道上上厕所的拖鞋声、宿舍中的鼾声，楼下的汽车声…。不一而足，似乎就是村上的文字，在寂静的夜空，旺盛的宣泄自己的存在。也曾经想象过，拿着村上的一本小说，在咖啡馆闲坐，揪着大把的光阴，听隔壁的人聊着王家卫，在言语中还夹杂一些英语…时髦的村上，感情也是时髦的，怀旧也带着时髦的色彩。 
<br>　　小说中美妙的意境和主人公微妙的心态，成了大学时候上课时，我揣摩的一个主题。村上说他所有的小说中的所有场景都是在他脑海中千锤百炼才勾勒出来的，因此电影艺术无法准确表达出来。我是相信的，所有的文字作者都认为影视作品不能完整的表达自己的初衷和色彩。但是，今天看村上的小说，在坚强的颓废后面，发现一种深深的溃败的痕迹，也在文字的背后行走。这个，或许是影视不能准确表达的关键点之一。 
<br>　　秋天的溃败是从收获的那天开始的，村上同样存在这样的问题。都市生活的轻松与压抑互动、精神的麻木与空洞、寻找生活节奏的努力，或者对着无边的泥沼，义无反顾的走下去，在淡淡的苦涩中，透露一点幽默的痕迹。幽默，其实就是村上秋天收获的溃败的开始。村上在小说后面说《挪威的森林》是一部私人性质很浓的小说。因此，在小说中不可避免的夹杂作者的影子，作者的溃败是什么？是溃不成军的撤退的拥挤的场面，因为所有的情感交叉、纠集在一起，大脑无法准确的判断和收拾，慌不择路，是逃跑时候最常见的形式，文字也是这样的。这种溃败，是所有的道路都密密集集的排在面前，所有的思绪和情感飘舞在眼前，任何一种方向，都是一种独特的姿势，因此，选择反而成了一种痛苦的事情。凌乱的不知所云，不是文字大成者一种无上境界？溃败，不过是通向那种境界的一个必经之路。 
<br>　　村上是溃败的一个守望者。他的文字结构、语言和故事，深深的影响一些人，为他们栅守一道脆弱的栏杆，或许在生生不息的寻找中，忘记森林中的迷茫和无处排遣的情感，给自己一个生存的理由，是生活和文字关注的，也是生命应该关注的。毕竟，那种实践，不是一般人可以经历的，村上没有。所有的人，应该有村上曾经的丰富情感，但是很少有人有文字中那种荒诞的经历。年轻时候，给自己寻找一个真正生存的理由，或许比单纯的在别人的字里行间搜寻闲淡的谈资或者剩饭划算。自己的样子有自己的影子，村上的背影已经走入属于他的那个时代，这个，或许也是我从村上的故事中得到的一种启发。 
<br>　　不论哪种情感，自己的才是美好的。这种美好是所有人都有的，不过是文字表达能力较好的能稍微准确一点的表达而已，村上就是。既然这样，为什么我们不能固守自己的美好？况且，在重重的压力下，村上的生活态度、写作风格等许多地方可以商榷，可以窥见溃败的影子。 
<br>　　关于从社会的形态、意识、制度、政治等不同层面和角度对村上及其作品进行描述、分析、评论的已经有很多。以我卑微的高度，也只能谈谈自己对故事的一个见解了，还请大方之家指教。 
<br>　　与一个对村上接近崇拜的文学朋友共享。', '通过写信的方式，将自己的分崩离析的生活维系起来，是《挪威的森林》最大特色。文章中那些焰火一样的美丽、烟花一样的情感，是一条长长的小溪，穿行在都市之外的天空下。深居简出的主人公、浓厚的怀旧感伤色彩、冷峻的嘲讽、艰涩的调侃在冰冷的城市、无边的水泥构建的庞大的灰色建筑中，建立一个属于自己的不灭的精神的天堂。我很难想象，村上这个忠于老婆和家庭，白天跑步、独自在自己庭院中漫步的孤独的人，在日本的文学上道路上不经意的就留下自己的深深的足迹，成为物质文明高度发达的社会中，精神文明日益溃败的一个坚实的守望者。

